classdef PaperStudySceneStatistics
    %PAPERSTUDYSCENESTATISTICS Paired scene bootstrap and Holm correction.
    %
    % Pixels remain descriptive. Each bootstrap replicate resamples complete
    % scenes with replacement and preserves candidate/baseline pairing.
    % Traceability: algo/main.tex Sec. 10.6 statistical comparison;
    % paper_study_v1 statistics/commonPromotion; D057 and D066.

    methods (Static)
        function result = evaluate(summary, comparisons, policy, options)
            arguments
                summary table {mustBePaperStudySceneSummary}
                comparisons table {mustBePaperStudyComparisons}
                policy (1, 1) struct {mustBePaperStudyStatisticsPolicy}
                options.RetainBootstrapSamples (1, 1) logical = true
            end

            b = policy.statistics.bootstrapReplicates;
            seed = policy.statistics.bootstrapSeed;
            confidence = policy.statistics.confidenceLevel;
            alpha = 1 - confidence;
            m = height(comparisons);
            rows = cell(m, 1);
            samples = cell(m, 1);
            state = rng;
            cleanup = onCleanup(@() rng(state));
            rng(seed, "twister");
            for k = 1:m
                c = summary(summary.Method == comparisons.Candidate(k) ...
                    & summary.Stage == comparisons.Stage(k), :);
                d = summary(summary.Method == comparisons.Baseline(k) ...
                    & summary.Stage == comparisons.Stage(k), :);
                [scene, ic, id] = intersect(c.Case, d.Case, "stable");
                ce = c.EndpointEpeRmsePixels(ic);
                be = d.EndpointEpeRmsePixels(id);
                cc = c.Coverage(ic);
                bc = d.Coverage(id);
                n = numel(scene);
                if n < 1
                    error("PaperStudySceneStatistics:InvalidComparison", ...
                        "Comparison %s has no paired scene metrics.", ...
                        comparisons.Direction(k));
                end
                complete = all(isfinite([ce; be; cc; bc]), "all");
                if complete
                    draw = randi(n, n, b);
                    br = 1 - mean(ce(draw), 1) ./ mean(be(draw), 1);
                    point = 1 - mean(ce) ./ mean(be);
                    p = (1 + nnz(br <= 0)) ./ (b + 1);
                    lo = PaperStudySceneStatistics.percentile( ...
                        br, 100 .* alpha ./ 2);
                    hi = PaperStudySceneStatistics.percentile( ...
                        br, 100 .* (1 - alpha ./ 2));
                else
                    br = nan(1, b);
                    point = NaN;
                    p = 1;
                    lo = NaN;
                    hi = NaN;
                end
                rows{k} = table(comparisons.Direction(k), ...
                    comparisons.Candidate(k), comparisons.Baseline(k), ...
                    comparisons.Stage(k), n, ...
                    nnz(isfinite(ce) & isfinite(be) ...
                    & isfinite(cc) & isfinite(bc)), complete, ...
                    mean(ce), mean(be), point, ...
                    mean(be - ce), mean(ce < be), ...
                    mean(bc - cc), max(ce - be), p, lo, hi, ...
                    VariableNames=["Direction", "Candidate", "Baseline", ...
                    "Stage", "SceneCount", "FiniteSceneCount", ...
                    "CompleteEvidence", "CandidateMeanEpePixels", ...
                    "BaselineMeanEpePixels", "RelativeImprovement", ...
                    "MeanPairedImprovementPixels", ...
                    "ImprovedSceneFraction", "MeanCoverageLoss", ...
                    "MaximumSceneEpeIncreasePixels", ...
                    "OneSidedBootstrapPValue", ...
                    "UncorrectedLowerRelativeImprovement", ...
                    "UncorrectedUpperRelativeImprovement"]);
                samples{k} = br;
            end
            t = vertcat(rows{:});
            [~, order] = sort(t.OneSidedBootstrapPValue);
            rank = zeros(m, 1);
            rank(order) = (1:m).';
            localAlpha = alpha ./ (m - rank + 1);
            adjusted = zeros(m, 1);
            running = 0;
            for j = 1:m
                k = order(j);
                running = max(running, ...
                    (m - j + 1) .* t.OneSidedBootstrapPValue(k));
                adjusted(k) = min(running, 1);
            end
            correctedLower = zeros(m, 1);
            correctedUpper = zeros(m, 1);
            for k = 1:m
                correctedLower(k) = ...
                    PaperStudySceneStatistics.percentile( ...
                    samples{k}, 100 .* localAlpha(k) ./ 2);
                correctedUpper(k) = ...
                    PaperStudySceneStatistics.percentile( ...
                    samples{k}, 100 .* (1 - localAlpha(k) ./ 2));
            end
            gate = policy.acceptance.commonPromotion;
            t.HolmRank = rank;
            t.HolmLocalAlpha = localAlpha;
            t.HolmAdjustedPValue = adjusted;
            t.HolmCorrectedLowerRelativeImprovement = correctedLower;
            t.HolmCorrectedUpperRelativeImprovement = correctedUpper;
            t.PassesMinimumRelativeImprovement = ...
                t.CompleteEvidence & t.RelativeImprovement >= ...
                gate.minimumHeldoutRelativeEpeImprovement;
            t.PassesCorrectedInterval = ...
                t.CompleteEvidence & correctedLower > 0;
            t.PassesCoverage = t.CompleteEvidence ...
                & t.MeanCoverageLoss <= ...
                gate.maximumMeanCoverageLoss;
            t.PassesMaximumSceneIncrease = ...
                t.CompleteEvidence ...
                & t.MaximumSceneEpeIncreasePixels <= ...
                gate.maximumHeldoutSceneEpeIncreasePixels;
            t.PassesCommonPromotion = ...
                t.PassesMinimumRelativeImprovement ...
                & t.PassesCorrectedInterval & t.PassesCoverage ...
                & t.PassesMaximumSceneIncrease;
            if ~options.RetainBootstrapSamples
                samples = cell(0, 1);
            end
            result = struct( ...
                "Comparisons", t, ...
                "BootstrapRelativeImprovement", {samples}, ...
                "BootstrapReplicates", b, ...
                "BootstrapSeed", seed, ...
                "ConfidenceLevel", confidence, ...
                "Correction", ...
                "Holm family-wise alpha 0.05 across four direction tests", ...
                "ResamplingUnit", "scene", ...
                "PixelInference", "descriptive only");
            clear cleanup
        end
    end

    methods (Static, Access = private)
        function y = percentile(x, q)
            x = sort(x(isfinite(x)));
            if isempty(x)
                y = NaN;
                return
            end
            u = 1 + (numel(x) - 1) .* q ./ 100;
            a = floor(u);
            b = ceil(u);
            y = x(a) + (u - a) .* (x(b) - x(a));
        end
    end
end

function mustBePaperStudySceneSummary(t)
required = ["Case", "Method", "Stage", ...
    "EndpointEpeRmsePixels", "Coverage"];
if isempty(t) || ~all(ismember(required, ...
        string(t.Properties.VariableNames)))
    error("PaperStudySceneStatistics:InvalidSummary", ...
        "Case/method/stage endpoint and coverage rows are required.");
end
end

function mustBePaperStudyComparisons(t)
required = ["Direction", "Candidate", "Baseline", "Stage"];
if height(t) ~= 4 || ~all(ismember(required, ...
        string(t.Properties.VariableNames))) ...
        || numel(unique(t.Direction)) ~= 4
    error("PaperStudySceneStatistics:InvalidComparisons", ...
        "Exactly four uniquely named direction comparisons are required.");
end
end

function mustBePaperStudyStatisticsPolicy(s)
if ~all(isfield(s, ["statistics", "acceptance"])) ...
        || ~isfield(s.acceptance, "commonPromotion") ...
        || s.statistics.bootstrapReplicates < 1 ...
        || s.statistics.confidenceLevel <= 0 ...
        || s.statistics.confidenceLevel >= 1
    error("PaperStudySceneStatistics:InvalidPolicy", ...
        "The frozen bootstrap and common-promotion policy is required.");
end
end
